var stack = new Stack<int>();

// Push — O(1)
stack.Push(10);
stack.Push(20);
stack.Push(30);

// Peek — O(1), não remove
int topo = stack.Peek();  // 30

// Pop — O(1)
int removido = stack.Pop();  // 30

// Verificar vazio
bool vazia = stack.Count == 0;

