// Go não tem Stack nativo; usa slice como pilha
var stack []int

// Push — O(1) amortizado
stack = append(stack, 10)
stack = append(stack, 20)
stack = append(stack, 30)

// Peek — O(1)
topo := stack[len(stack)-1]  // 30

// Pop — O(1)
removido := stack[len(stack)-1]
stack = stack[:len(stack)-1]  // 20

codeSnippets.javascript:
// Array como pilha — push/pop no final são O(1) amortizado
const stack = [];

// Push
stack.push(10);
stack.push(20);
stack.push(30);

// Peek
const topo = stack[stack.length - 1];  // 30

// Pop
const removido = stack.pop();  // 30

console.log(stack);  // [10, 20]
